// 单个IP人物生成 - ComfyUI 工作流构建
const inputData = $input.first()?.json || {};
const body = inputData.body || {};

const role = (body.character_name || body.name || body.role || 'poppy').toLowerCase();
const rawPrompt = body.prompt || '';
const userNegative = body.negative_prompt || 'blurry, 3d, realistic, complex textures, bad anatomy, deformed, shadows, gradients, background details';

// 角色触发词映射
const triggerWords = {
  poppy: 'cj_vector_style, poppy_character, minimalist, solid black dot eyes, no pupils',
  edi: 'cj_vector_style, edi_character',
  rolly: 'cj_vector_style, rolly_character',
  ace: 'cj_vector_style, ace_character',
  milo: 'cj_vector_style, milo_character'
};

const userPrompt = `${triggerWords[role] || `${role}_character`}, ${rawPrompt}`;

// 构建单个角色的 ComfyUI 工作流
const workflow = {
  "1": { "inputs": { "unet_name": "z_image_turbo_bf16.safetensors", "weight_dtype": "default" }, "class_type": "UNETLoader" },
  "2": { "inputs": { "vae_name": "ae.safetensors" }, "class_type": "VAELoader" },
  "3": { "inputs": { "clip_name": "qwen_3_4b.safetensors", "type": "lumina2", "device": "default" }, "class_type": "CLIPLoader" },
  "4": { "inputs": { "shift": 3, "model": ["1", 0] }, "class_type": "ModelSamplingAuraFlow" },
  "5": { "inputs": { "width": body.width || 1024, "height": body.height || 1024, "batch_size": 1 }, "class_type": "EmptySD3LatentImage" },
  "7": { "inputs": { "text": userNegative, "clip": ["3", 0] }, "class_type": "CLIPTextEncode" },
  "101": { "inputs": { "lora_name": `${role}.safetensors`, "strength_model": 0.8, "strength_clip": 1, "model": ["4", 0], "clip": ["3", 0] }, "class_type": "LoraLoader" },
  "102": { "inputs": { "text": userPrompt, "clip": ["101", 1] }, "class_type": "CLIPTextEncode" },
  "103": { "inputs": { "seed": Math.floor(Math.random() * 100000000000000), "steps": 20, "cfg": 1.5, "sampler_name": "euler", "scheduler": "simple", "denoise": 1, "model": ["101", 0], "positive": ["102", 0], "negative": ["7", 0], "latent_image": ["5", 0] }, "class_type": "KSampler" },
  "104": { "inputs": { "samples": ["103", 0], "vae": ["2", 0] }, "class_type": "VAEDecode" },
  "105": { "inputs": { "filename_prefix": `Asset_${role}`, "images": ["104", 0] }, "class_type": "SaveImage" }
};

const comfyuiUrl = 'https://vcbj5meqyp1y7ifw-8188.container.x-gpu.com';

return [{
  json: {
    comfyui_url: comfyuiUrl,
    comfyui_payload: { prompt: workflow },
    debug: {
      role_identified: role,
      final_prompt: userPrompt,
      lora_used: `${role}.safetensors`
    }
  }
}];

const comfyuiResponse = $input.first()?.json || {};
const promptId = comfyuiResponse?.prompt_id || comfyuiResponse?.id;

const prepNode = $('🎨 准备生成参数').all();
let comfyuiUrl = '';
if (prepNode && prepNode.length > 0) {
  comfyuiUrl = prepNode[0]?.json?.comfyui_url || '';
}

return [{
  json: {
    executionId: promptId,
    comfyuiUrl: comfyuiUrl,
    workflowType: 'single-ip-character',
    status: 'submitted'
  }
}];
